{
  "domain_analysis": {
    "business_context": "A logistics platform introducing automated route optimization for drivers at shift start, with dynamic recalculation triggers, customer notification windows, vehicle-class enforcement, and configurable stop-time estimates. This spans multiple bounded contexts: route planning, fleet/driver management, delivery lifecycle, and customer notifications.",
    "bounded_context": "Multiple contexts identified: (1) Route Planning — owns route calculation, optimization, recalculation triggers, stop-time estimates; (2) Fleet Management — owns driver shifts, vehicle classes, zone assignments, licensing constraints; (3) Delivery Management — owns delivery lifecycle, pending/failed/completed states, zone assignment; (4) Customer Notification — owns notification triggers, delivery proximity windows. The feature described is an orchestration across all four.",
    "ubiquitous_language": [
      { "term": "Shift", "definition": "A bounded work period during which a driver is active and eligible to receive route assignments. A shift has a start and end, and is the lifecycle anchor for route assignment." },
      { "term": "Zone", "definition": "A geographic area that scopes both drivers and deliveries. A driver operates within a zone during their shift; deliveries belong to a zone based on destination." },
      { "term": "Optimized Route", "definition": "An ordered sequence of delivery stops calculated by the system to minimize total travel time/distance for a driver within their zone during their shift." },
      { "term": "Pending Delivery", "definition": "A delivery that has been created and is awaiting assignment to a driver's route. It exists within a zone and has not yet been picked up or failed." },
      { "term": "Failed Delivery", "definition": "A delivery that was attempted but could not be completed (e.g., recipient unavailable, access denied). Triggers route recalculation as the stop is removed or deprioritized." },
      { "term": "Route Recalculation", "definition": "The act of recomputing the optimized route in response to a material change: new delivery added, delivery failure, or driver deviation." },
      { "term": "Driver Deviation", "definition": "When a driver's actual position or stop sequence diverges from the suggested optimized route beyond a threshold. This is a domain event, not merely a GPS reading." },
      { "term": "Next 3 Stops Window", "definition": "A proximity-based notification trigger: when a delivery is among the next 3 stops on the driver's active route, the customer receives a notification." },
      { "term": "Vehicle Class", "definition": "A classification of a vehicle's cargo capability (e.g., motorcycle, van, truck, freight). Determines which deliveries are physically eligible for a driver." },
      { "term": "Licensed Vehicle Class", "definition": "The vehicle class(es) a driver is authorized to operate, based on licensing and the vehicle assigned to their shift." },
      { "term": "Stop Time Estimate", "definition": "The expected duration a driver spends at each delivery stop. Defaults to 4 minutes but is overridable per zone by the operations team." },
      { "term": "Operations Team", "definition": "Internal stakeholders who manage zone-level configuration, including stop time overrides and potentially other operational parameters." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A driver MUST only be assigned deliveries whose cargo requirements are compatible with their licensed vehicle class.",
      "invariant": true,
      "invariant_justification": "Assigning a freight shipment to a motorcycle is a physical impossibility and potentially a safety/legal violation. This is not a policy preference — it is a hard constraint rooted in physical reality and regulatory compliance. Violating it produces a corrupt system state where an unexecutable delivery is on a route.",
      "testable_assertion": "For every delivery on a driver's route, delivery.requiredVehicleClass must be within driver.licensedVehicleClasses."
    },
    {
      "id": "BR-2",
      "rule": "A driver MUST only be assigned deliveries within their assigned zone.",
      "invariant": true,
      "invariant_justification": "Zone boundaries define operational scope. Assigning cross-zone deliveries breaks the optimization model, violates SLA assumptions, and creates accountability gaps. A driver outside their zone has no obligation or logistical basis to be there.",
      "testable_assertion": "For every delivery on a driver's route, delivery.zone must equal driver.currentShift.zone."
    },
    {
      "id": "BR-3",
      "rule": "When a driver starts their shift, the system MUST automatically generate an optimized route from all pending deliveries in their zone that are compatible with their vehicle class.",
      "invariant": false,
      "invariant_justification": "The automatic assignment at shift start is a business workflow policy. The business could decide to require manual confirmation or staggered assignment. The system would not be corrupt without it — just less efficient.",
      "testable_assertion": "Within T seconds of a driver's shift starting, a route containing all eligible pending deliveries in their zone is created and assigned to them."
    },
    {
      "id": "BR-4",
      "rule": "The route MUST be recalculated when a new pending delivery is added to the driver's zone.",
      "invariant": false,
      "invariant_justification": "This is an optimization policy. The business could choose to batch recalculations or defer them. Not recalculating does not corrupt state — it just means the route is suboptimal.",
      "testable_assertion": "When a new delivery is created in a zone with an active driver route, the route is recalculated within a defined SLA to include the new delivery."
    },
    {
      "id": "BR-5",
      "rule": "The route MUST be recalculated when a delivery on the route is marked as failed.",
      "invariant": false,
      "invariant_justification": "Same as BR-4 — optimization policy. A stale route with a failed stop is inefficient but not corrupt.",
      "testable_assertion": "When a delivery on an active route transitions to 'failed', the route is recalculated excluding that delivery."
    },
    {
      "id": "BR-6",
      "rule": "The route MUST be recalculated when the driver manually deviates from the suggested route.",
      "invariant": false,
      "invariant_justification": "This is a responsiveness policy. The system could instead flag the deviation for manual review. State is not corrupted by a stale route — just inaccurate.",
      "testable_assertion": "When a deviation event is detected (driver skips a stop or travels to an off-route location), the route is recalculated from the driver's current position."
    },
    {
      "id": "BR-7",
      "rule": "Customers MUST be notified when their delivery enters the 'next 3 stops' window on the driver's active route.",
      "invariant": false,
      "invariant_justification": "Notification is a customer experience policy. The number '3' could be changed by product. Missing a notification does not corrupt delivery state.",
      "testable_assertion": "When a delivery moves into positions 1-3 on the active route (and was not previously in that window), a notification is sent to the customer exactly once."
    },
    {
      "id": "BR-8",
      "rule": "The default estimated stop time is 4 minutes per delivery stop, overridable per zone by the operations team.",
      "invariant": false,
      "invariant_justification": "This is a configurable operational parameter. Both the default and the override mechanism are policy decisions.",
      "testable_assertion": "Route time calculations use the zone-specific override if set; otherwise, 4 minutes. The operations team can set/update the override via a configuration interface."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A driver starts their shift in zone A with a motorcycle, and there are 5 pending deliveries in zone A (3 small-parcel, 2 freight)",
      "when": "The system generates the initial route",
      "then": "The route contains only the 3 small-parcel deliveries (compatible with motorcycle), ordered by optimization algorithm, and the 2 freight deliveries remain unassigned"
    },
    {
      "id": "AC-2",
      "given": "A driver has an active route with 8 stops in zone B",
      "when": "A new pending delivery is added to zone B that is compatible with the driver's vehicle class",
      "then": "The route is recalculated to include the new delivery in its optimal position, and existing stop ordering may change"
    },
    {
      "id": "AC-3",
      "given": "A driver has an active route and delivery at stop 5 is marked as failed",
      "when": "The failure event is processed",
      "then": "The route is recalculated excluding the failed delivery, and remaining stops are reoptimized from the driver's current position"
    },
    {
      "id": "AC-4",
      "given": "A driver has an active route [A, B, C, D, E] and skips stop B, proceeding directly to C",
      "when": "The deviation is detected",
      "then": "The route is recalculated from the driver's current position, and stop B is repositioned optimally in the remaining route (not dropped)"
    },
    {
      "id": "AC-5",
      "given": "A driver has an active route with 10 stops and customer X's delivery is at position 5",
      "when": "The driver completes stop 1 and customer X's delivery moves to position 4, then completes stop 2 moving X to position 3",
      "then": "Customer X receives a notification exactly once — when their delivery first enters position 3 (the boundary of the 'next 3' window)"
    },
    {
      "id": "AC-6",
      "given": "Zone C has a stop time override of 6 minutes and zone D uses the default",
      "when": "Routes are calculated for drivers in both zones",
      "then": "Zone C route ETAs use 6 minutes per stop; zone D route ETAs use 4 minutes per stop"
    },
    {
      "id": "AC-7",
      "given": "A route recalculation causes delivery Y to move from position 5 to position 2 (entering the 'next 3' window)",
      "when": "The recalculated route is published",
      "then": "Customer Y is notified that their delivery is approaching"
    },
    {
      "id": "AC-8",
      "given": "Two drivers are active in the same zone, driver 1 (van) and driver 2 (motorcycle)",
      "when": "A new freight delivery arrives in the zone",
      "then": "Only driver 1's route is recalculated to include it; driver 2's route is unaffected"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A new delivery arrives in a zone where multiple drivers are active — which driver gets it?",
      "expected_behavior": "The spec does not address multi-driver zones. The system needs a delivery-to-driver assignment strategy (nearest driver, least-loaded, etc.). This is a critical gap that must be resolved before implementation."
    },
    {
      "scenario": "A route recalculation is triggered while a previous recalculation is still in progress.",
      "expected_behavior": "The system must either queue recalculations or cancel-and-restart. Concurrent recalculations for the same route must not produce conflicting route states. The latest trigger's context must win."
    },
    {
      "scenario": "A driver deviates, triggering recalculation, but then returns to the original route before recalculation completes.",
      "expected_behavior": "The recalculation should still complete using the driver's position at the time of calculation. Rapid oscillation should be debounced to avoid route thrashing."
    },
    {
      "scenario": "A delivery is added and immediately fails (e.g., pre-delivery cancellation) while recalculation is in flight.",
      "expected_behavior": "The system must handle compound events. The recalculated route must reflect the latest known state of all deliveries, not the state at trigger time."
    },
    {
      "scenario": "Customer notification is triggered, but then a recalculation moves the delivery OUT of the 'next 3' window.",
      "expected_behavior": "The notification has already been sent and cannot be unsent. The spec does not mention a retraction notification. Product must decide: is a 'your delivery has been delayed' notification needed?"
    },
    {
      "scenario": "A driver's shift ends mid-route with remaining deliveries.",
      "expected_behavior": "Not addressed in the spec. Remaining deliveries must return to 'pending' status and become eligible for reassignment. Any customers in the 'next 3' window who were notified need a delay notification."
    },
    {
      "scenario": "All deliveries in a zone fail, leaving the driver with an empty route.",
      "expected_behavior": "The driver should have an empty/idle route state. The system should not error. The driver remains available if new deliveries arrive."
    },
    {
      "scenario": "What constitutes a 'deviation'? Is it distance-based, sequence-based, or time-based?",
      "expected_behavior": "The spec says 'manually deviates from the suggested route' but does not define the threshold. This needs a clear definition: e.g., skipping the next stop, traveling >X meters off-route, or not arriving at the next stop within Y minutes of ETA."
    },
    {
      "scenario": "The operations team changes the zone stop-time override while drivers have active routes.",
      "expected_behavior": "The spec does not clarify if active routes should be recalculated with the new time. Recommend: active routes keep their calculation but next recalculation uses the updated value."
    },
    {
      "scenario": "A delivery is eligible for multiple zones (e.g., on a zone boundary).",
      "expected_behavior": "Each delivery must belong to exactly one zone. Zone assignment must be deterministic and unambiguous to prevent duplicate assignment to drivers in adjacent zones."
    }
  ],

  "business_impact": {
    "financial": "Route optimization directly reduces fuel costs, increases deliveries-per-shift (revenue throughput), and reduces overtime. Incorrect vehicle-class matching could expose the company to regulatory fines and insurance liability. The 4-minute default stop time affects capacity planning — if underestimated, routes will consistently overrun, causing cascading SLA breaches.",
    "operational": "Real-time recalculation introduces computational load and requires reliable geolocation infrastructure. Operations team needs a zone configuration interface. The deviation detection mechanism requires GPS streaming and threshold tuning — too sensitive creates route thrashing, too lenient defeats the purpose. Multi-driver zone assignment logic is a critical operational gap.",
    "user": "Customers receive proactive delivery proximity notifications, improving satisfaction and reducing 'where is my package' support calls. Drivers receive clear, optimized routes reducing cognitive load. However, frequent recalculations mid-shift could frustrate drivers if the route changes constantly. Notification accuracy directly impacts customer trust — a false 'arriving soon' erodes confidence.",
    "risk": "Vehicle-class violation is a safety/legal risk (invariant). Notification sent prematurely then delivery delayed is a customer trust risk. Race conditions in recalculation could produce inconsistent route states. The spec has significant gaps around multi-driver zones and deviation definition that pose high implementation risk if guessed wrong.",
    "stakeholders_affected": [
      { "group": "Drivers", "impact": "Primary users — receive auto-assigned routes, must trust optimization quality. Frequent recalculations may cause frustration. Must not receive physically impossible deliveries." },
      { "group": "Customers", "impact": "Receive proximity notifications. Accuracy of 'next 3 stops' directly affects their planning (e.g., staying home for delivery). False positives erode trust." },
      { "group": "Operations Team", "impact": "Gains zone-level configuration control (stop time overrides). Needs tooling to manage this. May need escalation paths when routes fail." },
      { "group": "Dispatch/Planning", "impact": "Loses manual control over driver assignments. Needs confidence in the optimization algorithm. May need override capability for edge cases." },
      { "group": "Finance/Compliance", "impact": "Vehicle class enforcement is a compliance requirement. Route efficiency directly affects cost per delivery KPI." }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The spec provides a solid feature narrative but has multiple critical ambiguities: (1) no multi-driver assignment strategy, (2) no deviation definition/threshold, (3) no shift-end handling, (4) no notification retraction policy, (5) no concurrency strategy for recalculation triggers. These are not minor details — they represent core behavioral decisions that if guessed wrong will require significant rework. The vehicle-class constraint and notification window are well-defined. The recalculation triggers are clear in WHEN but ambiguous in HOW.",
    "high_confidence_areas": [
      "Vehicle class constraint is a hard invariant — unambiguous",
      "Zone scoping for driver-delivery matching",
      "Three recalculation triggers are clearly enumerated",
      "Customer notification trigger at 'next 3 stops' boundary",
      "Stop time default and override mechanism"
    ],
    "low_confidence_areas": [
      "Multi-driver zone assignment strategy is completely unspecified",
      "Deviation detection threshold and mechanism undefined",
      "Shift lifecycle boundaries (end-of-shift, break) not addressed",
      "Notification retraction when delivery leaves the window after recalculation",
      "Recalculation concurrency and debouncing strategy",
      "Whether 'next 3 stops' is absolute position or relative to completion"
    ],
    "assumptions": [
      "Each driver operates in exactly one zone per shift",
      "A delivery belongs to exactly one zone",
      "Vehicle class is determined at shift start and does not change mid-shift",
      "Route optimization considers travel distance/time, not delivery priority or SLA deadlines",
      "The 'next 3 stops' notification is sent once per customer per route lifecycle, not re-sent on recalculation if they remain in the window"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "Multi-driver zone assignment: When multiple drivers are active in the same zone, the spec does not define how a new delivery is assigned to a specific driver. This is a fundamental routing decision — nearest driver? least-loaded? vehicle-class-then-nearest? Without this, the feature cannot be correctly implemented for any zone with more than one driver.",
      "affected_stakeholders": ["Drivers", "Customers", "Dispatch/Planning"],
      "options": [
        "Nearest driver by current GPS position",
        "Least-loaded driver (fewest remaining stops)",
        "Best-fit considering vehicle class, proximity, and current load",
        "Dispatch manually assigns, system only optimizes within a driver's assigned set"
      ],
      "recommendation": "Best-fit algorithm considering vehicle class eligibility first (hard filter), then optimizing across proximity and load balance. But product must confirm."
    },
    {
      "type": "ambiguity",
      "description": "Deviation detection definition: 'Driver manually deviates from the suggested route' has no measurable threshold. Is it triggered by skipping a stop? By GPS distance from the expected path? By time overrun? The choice dramatically affects recalculation frequency and driver experience.",
      "affected_stakeholders": ["Drivers", "Operations Team"],
      "options": [
        "Sequence-based: driver visits stops out of suggested order",
        "Distance-based: driver is >X meters from expected route path",
        "Stop-skip: driver passes the geofence of stop N+1 without completing stop N",
        "Hybrid: any of the above"
      ],
      "recommendation": "Stop-skip detection (driver arrives at a stop that is not next in sequence) as the primary trigger — it is the most deterministic and least noisy. Distance-based deviation as secondary with a generous threshold to catch true off-route scenarios."
    },
    {
      "type": "missing_context",
      "description": "Shift lifecycle boundaries are not addressed. What happens to the route and its deliveries when a driver's shift ends? What about breaks? What if a shift is extended? This affects delivery SLAs and customer notifications.",
      "affected_stakeholders": ["Drivers", "Customers", "Operations Team"],
      "options": [
        "Remaining deliveries auto-return to pending pool at shift end",
        "Driver must complete active route regardless of shift end time",
        "System warns driver N minutes before shift end if route will overrun"
      ],
      "recommendation": "System should calculate if the remaining route fits within the shift. If not, warn the driver and operations team. At shift end, undelivered stops return to pending. Customers previously notified should receive a delay notification."
    },
    {
      "type": "ambiguity",
      "description": "Notification retraction: If a customer is notified (delivery in 'next 3' window) but a recalculation moves their delivery out of the window, should a retraction/delay notification be sent? This directly affects customer trust.",
      "affected_stakeholders": ["Customers", "Operations Team"],
      "options": [
        "No retraction — accept the inaccuracy as rare",
        "Send a 'delivery delayed' notification when bumped out of the window",
        "Only notify at position 1 (next stop) to minimize false positives"
      ],
      "recommendation": "Send a 'delivery time updated' notification if a previously-notified customer is moved out of the 3-stop window. Silence in this case is worse than over-communication."
    }
  ],

  "rejection_reasons": []
}

